  ('investigation-d5dfc642-moex-00119', 'investigation-d5dfc642', 'investigation-d5dfc642-moex-111-44c4f898', 'sub-investigation-d5dfc642-04', NULL, 'single_choice', '憲法並無明文規定下列何者？', '["國民", "領土", "國旗", "國徽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:50+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "409", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "法律實務組"}'::jsonb, NULL),
  ('investigation-d5dfc642-moex-00120', 'investigation-d5dfc642', 'investigation-d5dfc642-moex-111-44c4f898', 'sub-investigation-d5dfc642-04', NULL, 'single_choice', '憲法第159條規定：「國民受教育之機會，一律平等」。有關本條規定之「受教育」係指下列何者？', '["僅指憲法第21條所稱之國民教育", "係指國民教育以外之其他階段教育", "係指未受基本教育之國民所受之補習教育", "係指包含碩士班教育在內之各階段教育"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:50+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "409", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "法律實務組"}'::jsonb, NULL),
  ('investigation-d5dfc642-moex-00121', 'investigation-d5dfc642', 'investigation-d5dfc642-moex-111-44c4f898', 'sub-investigation-d5dfc642-04', NULL, 'single_choice', '依司法院釋字第588號解釋，立法機關得基於下列何者目的，藉由限制人民自由之管收措施，以貫徹人民 法定義務之履行？', '["社會之治安", "金融之秩序", "重大之公益", "經濟之發展"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:50+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "409", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "法律實務組"}'::jsonb, NULL),
  ('investigation-d5dfc642-moex-00122', 'investigation-d5dfc642', 'investigation-d5dfc642-moex-111-44c4f898', 'sub-investigation-d5dfc642-04', NULL, 'single_choice', '司法院大法官依憲法第22條曾承認之非明文權利，不包括下列何者？', '["環境權", "人格權", "契約自由", "婚姻自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:50+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "409", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "法律實務組"}'::jsonb, NULL),
  ('investigation-d5dfc642-moex-00123', 'investigation-d5dfc642', 'investigation-d5dfc642-moex-111-44c4f898', 'sub-investigation-d5dfc642-04', NULL, 'single_choice', '關於法律保留原則，下列敘述，何者最為正確？', '["涉及人身自由之限制，應以法律定之，屬於國會保留。惟法律已有明文規定者，亦得以法律具體明確之 授權委由主管機關執行之", "涉及財產權之限制，應以法律定之，屬於國會保留", "對人民處以行政裁罰，處罰構成要件應以法律定之，屬於國會保留", "以不確定法律概念作為規範內容，應視不確定法律概念的目的、內容、範圍是否具體明確"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:50+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "409", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "法律實務組"}'::jsonb, NULL),
  ('investigation-d5dfc642-moex-00124', 'investigation-d5dfc642', 'investigation-d5dfc642-moex-111-44c4f898', 'sub-investigation-d5dfc642-04', NULL, 'single_choice', '依司法院大法官解釋，對於採取某些分類標準之法規範，應加強審查其是否符合平等保障之要求，下列何 者非屬之？', '["分類涉及難以改變之個人特徵", "分類屬於受有事實上或法律上之排斥或歧視者", "分類為社會上孤立隔絕之少數且為政治上之弱勢", "分類涉及國家考試之考選專業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:50+00:00", "source_pdf_sha1": "0abddb913603", "answer_pdf_sha1": "5fc37c6ea5d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "409", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識與英文(包括中華民國憲法、法學緒論、兩岸關係、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "法律實務組"}'::jsonb, NULL)
